"use client";

import * as React from "react";
import Link from "next/link";
import {
  ArrowRight,
  CircleDot,
  Facebook,
  Instagram,
  Linkedin,
  MessageCircle,
  MoreVertical,
  Paperclip,
} from "lucide-react";
import { cn } from "@/lib/utils";

/* ── types ───────────────────────────────────────────────────── */

type Action = { href: string; label: string };

export interface FloatingCardsHeroProps {
  /** Text shown inside the announcement pill */
  announcement?: string;
  /** Optional link for the announcement pill */
  announcementHref?: string;
  /** Main headline */
  title: React.ReactNode;
  /** Subtitle / description text */
  description?: string;
  /** Primary CTA button */
  primaryAction?: Action;
  /** Override the default scattered decorations. Pass `false` to hide. */
  decorations?: React.ReactNode | false;
  className?: string;
}

/* ── icons ────────────────────────────────────────────────────── */

function BoltIcon({ className }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 30"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      aria-hidden
    >
      <defs>
        <linearGradient
          id="bolt-shine"
          x1="0"
          y1="0"
          x2="24"
          y2="30"
          gradientUnits="userSpaceOnUse"
        >
          <stop offset="0" stopColor="#7BD1FF" />
          <stop offset="1" stopColor="#7BD1FF" stopOpacity="0" />
        </linearGradient>
      </defs>
      <path
        d="M19.4 7H15.55a.6.6 0 0 1-.59-.69l.78-5.13a.95.95 0 0 0-.94-1.08H9.05a.95.95 0 0 0-.94.81L6.25 13.18a.95.95 0 0 0 .94 1.07h3.78c.39 0 .7.31.7.7v6.53c0 .72.94.97 1.3.36l7.65-13.05a.95.95 0 0 0-.82-1.43Z"
        fill="#25A18E"
      />
      <path
        d="M19.4 7H15.55a.6.6 0 0 1-.59-.69l.78-5.13a.95.95 0 0 0-.94-1.08H9.05a.95.95 0 0 0-.94.81L6.25 13.18a.95.95 0 0 0 .94 1.07h3.78c.39 0 .7.31.7.7v6.53c0 .72.94.97 1.3.36l7.65-13.05a.95.95 0 0 0-.82-1.43Z"
        fill="url(#bolt-shine)"
        fillOpacity="0.7"
      />
    </svg>
  );
}

/* ── decorations ──────────────────────────────────────────────── */

function BoltCard({ className }: { className?: string }) {
  return (
    <div
      aria-hidden
      className={cn(
        "absolute flex size-16 items-center justify-center rounded-xl border border-white/70 bg-gradient-to-br from-white to-neutral-200 shadow-[0_5px_11px_rgba(0,0,0,0.10),0_20px_20px_rgba(0,0,0,0.09),0_44px_27px_rgba(0,0,0,0.05)] md:size-20 lg:size-28 lg:rounded-3xl",
        "dark:border-white/10 dark:from-neutral-800 dark:to-neutral-950",
        className,
      )}
    >
      <BoltIcon className="size-7 md:size-10 lg:size-14" />
    </div>
  );
}

const MEETING_ITEMS: ReadonlyArray<{ title: string; time: string }> = [
  { title: "Hero block installed", time: "10:30 | shadcn CLI" },
  { title: "Pricing section added", time: "14:30 | shadcn CLI" },
  { title: "Theme tokens applied", time: "18:30 | manual" },
];

function MeetingCard({
  headingTone = "bg-slate-200 dark:bg-slate-700/50",
  className,
}: {
  headingTone?: string;
  className?: string;
}) {
  return (
    <div
      aria-hidden
      className={cn(
        "absolute w-[220px] origin-top-left overflow-hidden rounded-2xl bg-card ring-1 ring-black/5 shadow-[0_7px_15px_rgba(51,51,51,0.10),0_27px_27px_rgba(51,51,51,0.09),0_60px_36px_rgba(51,51,51,0.05)] dark:ring-white/10",
        className,
      )}
    >
      <div
        className={cn(
          "flex h-10 items-center px-4 text-sm font-normal text-foreground/70",
          headingTone,
        )}
      >
        Activity
      </div>
      <div className="space-y-2 p-2">
        <p className="p-1 text-sm text-muted-foreground">Recent installs</p>
        {MEETING_ITEMS.map((item) => (
          <div key={item.title} className="px-1">
            <p className="text-base text-foreground">{item.title}</p>
            <p className="text-xs text-muted-foreground">{item.time}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

function SocialBadge({
  icon,
  rotation,
  gradient,
}: {
  icon: React.ReactNode;
  rotation: string;
  gradient: string;
}) {
  return (
    <div
      className={cn(
        "flex size-16 shrink-0 items-center justify-center rounded-2xl text-white shadow-lg shadow-black/20 ring-1 ring-white/10",
        gradient,
        rotation,
      )}
    >
      {icon}
    </div>
  );
}

function SocialStackCard({ className }: { className?: string }) {
  return (
    <div aria-hidden className={cn("absolute origin-top-left", className)}>
      <div className="relative h-[260px] w-[320px]">
        {/* folder tab */}
        <div className="absolute left-8 top-0 h-5 w-24 rounded-t-lg bg-card ring-1 ring-black/5 dark:ring-white/10" />
        {/* folder body */}
        <div className="absolute inset-x-0 top-4 h-[240px] rounded-2xl bg-card shadow-[0_7px_15px_rgba(51,51,51,0.10),0_27px_27px_rgba(51,51,51,0.09)] ring-1 ring-black/5 dark:ring-white/10">
          <p className="px-6 pt-6 text-base font-medium text-foreground">
            Community Channels
          </p>
          <div className="mt-8 flex items-center px-6">
            <SocialBadge
              icon={<MessageCircle className="size-7" strokeWidth={2.25} />}
              rotation="-rotate-[16deg]"
              gradient="bg-gradient-to-br from-indigo-500 to-violet-700"
            />
            <SocialBadge
              icon={<Instagram className="size-7" strokeWidth={2.25} />}
              rotation="rotate-[7deg] -ml-3"
              gradient="bg-gradient-to-br from-amber-400 via-rose-500 to-fuchsia-600"
            />
            <SocialBadge
              icon={<Facebook className="size-7" strokeWidth={2.25} />}
              rotation="-rotate-[10deg] -ml-3"
              gradient="bg-gradient-to-br from-sky-400 to-blue-700"
            />
            <SocialBadge
              icon={<Linkedin className="size-7" strokeWidth={2.25} />}
              rotation="rotate-[12deg] -ml-3"
              gradient="bg-gradient-to-br from-blue-500 to-blue-800"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

const INTERVIEW_REVIEWS: ReadonlyArray<{
  name: string;
  initials: string;
  caption: string;
  avatarTone: string;
}> = [
  {
    name: "Sara",
    initials: "SR",
    caption: "Shipped in a weekend.",
    avatarTone: "bg-gradient-to-br from-indigo-500 to-violet-600",
  },
  {
    name: "Theo",
    initials: "TM",
    caption: "Tokens just worked.",
    avatarTone: "bg-gradient-to-br from-emerald-500 to-teal-600",
  },
];

function InterviewNoteCard({ className }: { className?: string }) {
  return (
    <div aria-hidden className={cn("absolute origin-top-left", className)}>
      <div className="relative w-[300px]">
        <Paperclip
          className="absolute -top-4 left-5 z-10 size-10 -rotate-12 fill-neutral-300 stroke-neutral-500 drop-shadow"
          strokeWidth={1.25}
        />
        <div className="space-y-3">
          {INTERVIEW_REVIEWS.map((r, idx) => (
            <div
              key={idx}
              className="flex items-center justify-between rounded-xl bg-card p-4 ring-1 ring-black/5 shadow-[0_3px_8px_-1px_rgba(50,50,71,0.05),0_0_1px_rgba(12,26,75,0.24)] dark:ring-white/10"
            >
              <div className="flex items-center gap-3">
                <div
                  className={cn(
                    "flex size-11 items-center justify-center rounded-full text-xs font-semibold tracking-tight text-white ring-2 ring-card",
                    r.avatarTone,
                  )}
                >
                  {r.initials}
                </div>
                <div className="leading-tight">
                  <p className="text-sm font-semibold text-foreground">
                    {r.name}&apos;s Review
                  </p>
                  <p className="text-xs text-muted-foreground">{r.caption}</p>
                </div>
              </div>
              <MoreVertical className="size-4 text-muted-foreground" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function DefaultDecorations() {
  return (
    <>
      <BoltCard className="left-4 top-4 -rotate-[15deg] md:left-32 md:top-24" />
      <BoltCard className="bottom-60 right-6 rotate-[14deg] md:bottom-72 md:right-72 lg:right-96" />
      <MeetingCard
        headingTone="bg-slate-200 dark:bg-slate-700/50"
        className="-left-14 bottom-40 hidden rotate-[12deg] scale-90 md:-left-5 md:bottom-52 md:block"
      />
      <SocialStackCard className="-bottom-32 -left-32 rotate-[20deg] scale-[0.55] md:-bottom-32 md:-left-16 md:scale-90" />
      <MeetingCard
        headingTone="bg-sky-100 dark:bg-sky-900/40"
        className="-bottom-12 right-6 -rotate-[19deg] scale-75 md:-bottom-10 md:right-72 md:scale-100"
      />
      <InterviewNoteCard className="-bottom-32 -right-40 -rotate-[12deg] scale-75 md:-bottom-32 md:-right-4 md:scale-100" />
    </>
  );
}

/* ── component ───────────────────────────────────────────────── */

export function FloatingCardsHero({
  announcement,
  announcementHref,
  title,
  description,
  primaryAction,
  decorations,
  className,
}: FloatingCardsHeroProps) {
  const decorationsNode =
    decorations === false ? null : (decorations ?? <DefaultDecorations />);

  return (
    <section
      className={cn(
        "relative mx-auto mt-5 w-full overflow-hidden rounded-[35px] border border-border bg-background p-4 md:h-[912px] h-[710px]",
        className,
      )}
      aria-label="Hero"
    >
      {decorationsNode}

      <div className="relative z-10 flex h-5/6 w-full flex-col items-center justify-center text-center">
        {announcement && (
          <Link
            href={announcementHref ?? "#"}
            className="flex h-9 w-72 items-center justify-center gap-2 rounded-xl bg-emerald-400/40 text-[10px] font-semibold text-emerald-950 ring-1 ring-emerald-500/20 transition-colors hover:bg-emerald-400/60 md:h-10 md:w-[459px] md:gap-3 md:text-base dark:bg-emerald-500/20 dark:text-emerald-50 dark:ring-emerald-400/20 dark:hover:bg-emerald-500/30"
          >
            <CircleDot className="size-4 fill-emerald-600/30 text-emerald-700 md:size-5 dark:text-emerald-200" />
            {announcement}
          </Link>
        )}

        <h1 className="mt-8 w-full text-balance text-2xl font-bold tracking-tight text-foreground md:w-4/6 md:text-6xl">
          {title}
        </h1>

        {description && (
          <p className="mx-auto mt-9 w-[95%] max-w-2xl text-balance text-sm font-medium leading-[23px] tracking-tight text-muted-foreground md:text-lg">
            {description}
          </p>
        )}

        {primaryAction && (
          <Link
            href={primaryAction.href}
            className="mt-9 inline-flex h-12 w-56 items-center justify-center rounded-xl border border-emerald-700 bg-gradient-to-b from-emerald-500 to-emerald-700 text-base font-semibold text-white shadow-[0_4px_14.8px_rgba(0,0,0,0.2)] transition-transform hover:-translate-y-0.5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald-400 focus-visible:ring-offset-2"
          >
            {primaryAction.label}
            <ArrowRight className="ml-2 size-4" />
          </Link>
        )}
      </div>
    </section>
  );
}

export default FloatingCardsHero;
